&lt;p&gt;&lt;span style=&quot;text-decoration: underline;&quot;&gt;&lt;strong&gt;&lt;img style=&quot;max-width: 100%;&quot; src=&quot;https://i.imgur.com/GF7HrSj.jpg&quot; alt=&quot;&quot; width=&quot;300&quot;&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
